patch:
--- a/alu_64bit.v
+++ b/alu_64bit.v
@@ -1,16 +1,16 @@
 module alu_64bit (
   input [63:0] operand_x,
   input [63:0] operand_y,
   input [3:0] opcode,
   output reg [63:0] result
 );
-  always @(operand_x or opcode) begin
+  always @(operand_x or operand_y or opcode) begin
     case (opcode)
       4'h0: result = operand_x + operand_y;
       4'h1: result = operand_x - operand_y;
       4'h2: result = operand_x & operand_y;
       4'h3: result = operand_x | operand_y;
       4'h4: result = operand_x ^ operand_y;
       default: result = 64'b0;
     endcase
   end
 endmodule

